+  private getCursorOrder(orderBy: any) {
+    const entries: { field: string; direction: 'asc' | 'desc' }[] = [];
+    const orders = Array.isArray(orderBy) ? orderBy : [orderBy];
+    for (const order of orders) {
+      if (!order || typeof order !== 'object' || Array.isArray(order)) {
+        throw new BadRequestException('Invalid orderBy for cursor pagination');
+      }
+      for (const [field, value] of Object.entries(order)) {
+        const direction = this.getCursorDirection(value);
+        if (!direction || entries.some((entry) => entry.field === field)) {
+          throw new BadRequestException('Invalid orderBy for cursor pagination');
+        }
+        entries.push({ field, direction });
+      }
+    }
+    if (!entries.length) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+
+    const idField = this.crudConfig.id_field;
+    if (!entries.some((entry) => entry.field === idField)) {
+      entries.push({ field: idField, direction: 'asc' });
+    }
+    return entries;
+  }
+
+  private getCursorDirection(value: any): 'asc' | 'desc' | undefined {
+    if (value === 1 || typeof value === 'string' && value.toLowerCase().startsWith('asc')) {
+      return 'asc';
+    }
+    if (value === -1 || typeof value === 'string' && value.toLowerCase().startsWith('desc')) {
+      return 'desc';
+    }
+    return undefined;
+  }
+
+  private decodeCursor(
+    cursor: string,
+    order: { field: string; direction: 'asc' | 'desc' }[],
+  ): Record<string, any> {
+    if (
+      typeof cursor !== 'string' ||
+      !/^(?:[A-Za-z0-9+/]{4})*(?:[A-Za-z0-9+/]{2}==|[A-Za-z0-9+/]{3}=)?$/.test(
+        cursor,
+      )
+    ) {
+      throw new BadRequestException('Invalid cursor');
+    }
+    let values: Record<string, any>;
+    try {
+      values = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('Invalid cursor');
+    }
+    if (!values || typeof values !== 'object' || Array.isArray(values)) {
+      throw new BadRequestException('Invalid cursor');
+    }
+
+    const expectedSort = order
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (values.__sort !== expectedSort) {
+      throw new BadRequestException('Cursor orderBy does not match request');
+    }
+    if (!Object.prototype.hasOwnProperty.call(values, this.crudConfig.id_field)) {
+      throw new BadRequestException('Cursor is missing the entity ID');
+    }
+    for (const { field } of order) {
+      if (!Object.prototype.hasOwnProperty.call(values, field)) {
+        throw new BadRequestException('Cursor is missing a sort field');
+      }
+    }
+    return values;
+  }
+
+  private getCursorQuery(
+    order: { field: string; direction: 'asc' | 'desc' }[],
+    values: Record<string, any>,
+  ) {
+    return {
+      $or: order.map(({ field, direction }, index) => ({
+        $and: [
+          ...order.slice(0, index).map(({ field }) => ({
+            [field]: values[field],
+          })),
+          { [field]: { [direction === 'asc' ? '$gt' : '$lt']: values[field] } },
+        ],
+      })),
+    };
+  }
+
+  private encodeCursor(
+    entity: T,
+    order: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    const values = order.reduce(
+      (cursor, { field }) => ({ ...cursor, [field]: entity[field] }),
+      {} as Record<string, any>,
+    );
+    values.__sort = order
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    return Buffer.from(JSON.stringify(values)).toString('base64');
+  }
