  async $find(
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ): Promise<FindResponseDto<T>> {
    const opParams = this.getOpParams(opOptions, ctx);
    try {
      if (!opParams.options?.skipServiceHooks) {
        entity = await this.beforeReadHook(entity, ctx);
      }

      if (Array.isArray(entity[this.crudConfig.id_field])) {
        this.makeInQuery(entity[this.crudConfig.id_field], entity);
      }

      this.checkObjectForIds(entity);

      const em = opParams.em || this.entityManager.fork();
      const opts = this.getReadOptions(ctx, opParams);
      const cursor = opts.cursor;
      const hasCursor = cursor !== undefined;

      if (hasCursor && !opts.orderBy) {
        throw new BadRequestException('cursor requires orderBy');
      }
      if (hasCursor && opts.offset !== undefined) {
        throw new BadRequestException('cursor cannot be used with offset');
      }

      let cursorOrder: { field: string; direction: 'asc' | 'desc' }[];
      if (opts.orderBy && opts.limit) {
        cursorOrder = this.getCursorOrder(opts.orderBy);
        opts.orderBy = cursorOrder.reduce(
          (orderBy, { field, direction }) => ({
            ...orderBy,
            [field]: direction,
          }),
          {},
        );
      } else if (hasCursor) {
        cursorOrder = this.getCursorOrder(opts.orderBy);
        opts.orderBy = cursorOrder.reduce(
          (orderBy, { field, direction }) => ({
            ...orderBy,
            [field]: direction,
          }),
          {},
        );
      }

      if (hasCursor) {
        const cursorValues = this.decodeCursor(cursor, cursorOrder);
        entity = {
          $and: [entity, this.getCursorQuery(cursorOrder, cursorValues)],
        } as unknown as Partial<T>;
      }

      let result: FindResponseDto<T>;
      if (opts.limit) {
        const requestedLimit = opts.limit;
        const useCursorPagination = !!opts.orderBy;
        if (useCursorPagination) {
          opts.limit = requestedLimit + 1;
        }
        const res = await em.findAndCount(this.entity, entity, opts as any);
        const hasMore = useCursorPagination && res[0].length > requestedLimit;
        const data = hasMore ? res[0].slice(0, requestedLimit) : res[0];
        result = { data, total: res[1], limit: requestedLimit };
        if (hasMore) {
          result.nextCursor = this.encodeCursor(
            data[data.length - 1],
            cursorOrder,
          );
        }
      } else {
        const res = await em.find(this.entity, entity, opts as any);
        result = { data: res };
      }
      if (!opParams.options?.skipServiceHooks) {
        result = await this.afterReadHook(result, entity, ctx);
      }
      return result;
    } catch (e) {
      if (!opParams.options?.skipServiceHooks) {
        const res = await this.errorReadHook(entity, ctx, e);
        if (res) {
          return res;
        }
      }
      throw e;
    }
  }

  async $findIds(
    entity: Partial<T>,
    ctx: CrudContext<T>,
    opOptions: OpParams<T> = { secure: true },
    inheritance?: Inheritance,
  ): Promise<string[]> {
    const newOpts: OpParams<T> = {
      ...opOptions,
      options: {
        ...(opOptions.options || {}),
        fields: [this.crudConfig.id_field as any],
      },
    };
    const res = await this.$find(entity, ctx, newOpts);
